import React, { useState, useEffect } from "react";
import "./Navbar.css";

export default function Navbar({ wallet, onLaunchApp, activeSection }) {
    const [scrolled, setScrolled]       = useState(false);
    const [megaMenu, setMegaMenu]       = useState(null); // "how" | "tech" | "app"
    const [sidePanel, setSidePanel]     = useState(false);

    useEffect(() => {
        const fn = () => setScrolled(window.scrollY > 60);
        window.addEventListener("scroll", fn);
        return () => window.removeEventListener("scroll", fn);
    }, []);

    const navItems = [
        {
            id: "how",
            label: "How It Works",
            mega: {
                cols: [
                    {
                        heading: "The Process",
                        links: [
                            { label: "Upload to IPFS",        sub: "Pin your PDF via Pinata" },
                            { label: "Submit to Blockchain",   sub: "Sign with your wallet" },
                            { label: "Verify Precedence",      sub: "Public, trustless proof" },
                        ],
                    },
                    {
                        heading: "Technology",
                        links: [
                            { label: "IPFS & Content IDs",     sub: "SHA-256 fingerprinting" },
                            { label: "Smart Contracts",         sub: "Solidity on Polygon" },
                            { label: "Hardhat Framework",       sub: "Local dev & testing" },
                        ],
                    },
                ],
                image: "https://images.unsplash.com/photo-1639762681057-408e52192e55?w=600&q=80",
                imageCaption: "Immutable on-chain records",
            },
        },
        {
            id: "tech",
            label: "Technology",
            mega: {
                cols: [
                    {
                        heading: "Blockchain",
                        links: [
                            { label: "Ethereum Virtual Machine", sub: "EVM-compatible execution" },
                            { label: "Polygon Network",           sub: "Low-cost, fast finality" },
                            { label: "Solidity 0.8",              sub: "Smart contract language" },
                        ],
                    },
                    {
                        heading: "Storage & Identity",
                        links: [
                            { label: "IPFS Protocol",      sub: "Decentralised file storage" },
                            { label: "Pinata Pinning",     sub: "Guaranteed availability" },
                            { label: "Wallet Signatures",  sub: "Cryptographic authorship" },
                        ],
                    },
                ],
                image: "https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=600&q=80",
                imageCaption: "Built on proven cryptography",
            },
        },
        {
            id: "app",
            label: "Launch App",
            action: onLaunchApp,
        },
    ];

    return (
        <>
            <nav className={`navbar ${scrolled ? "navbar--scrolled" : ""}`}>
                <div className="navbar__brand">
                    <div className="navbar__logo">⛓</div>
                    <span className="navbar__name">Proof of Precedence</span>
                </div>

                <div className="navbar__center">
                    {navItems.map(item => (
                        <div
                            key={item.id}
                            className="navbar__item"
                            onMouseEnter={() => item.mega && setMegaMenu(item.id)}
                            onMouseLeave={() => setMegaMenu(null)}
                        >
                            <button
                                className={`navbar__link ${megaMenu === item.id ? "navbar__link--active" : ""}`}
                                onClick={item.action || (() => {})}
                            >
                                {item.label}
                                {item.mega && <span className="navbar__arrow">›</span>}
                            </button>

                            {item.mega && megaMenu === item.id && (
                                <div className="mega-menu">
                                    <div className="mega-menu__inner">
                                        {item.mega.cols.map(col => (
                                            <div className="mega-menu__col" key={col.heading}>
                                                <div className="mega-menu__heading">{col.heading}</div>
                                                {col.links.map(link => (
                                                    <div className="mega-menu__link" key={link.label}>
                                                        <span className="mega-menu__link-label">{link.label}</span>
                                                        <span className="mega-menu__link-sub">{link.sub}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        ))}
                                        <div className="mega-menu__image-col">
                                            <img src={item.mega.image} alt="" className="mega-menu__img" loading="lazy" />
                                            <span className="mega-menu__img-caption">{item.mega.imageCaption}</span>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                <div className="navbar__right">
                    {wallet ? (
                        <div className="navbar__wallet">
                            <span className="navbar__wallet-dot" />
                            {wallet.slice(0, 6)}…{wallet.slice(-4)}
                        </div>
                    ) : null}
                    <button
                        className="navbar__hamburger"
                        onClick={() => setSidePanel(true)}
                        aria-label="Open menu"
                    >
                        <span /><span /><span />
                    </button>
                </div>
            </nav>

            {/* ── SIDE PANEL ── */}
            <div className={`side-panel ${sidePanel ? "side-panel--open" : ""}`}>
                <div className="side-panel__backdrop" onClick={() => setSidePanel(false)} />
                <div className="side-panel__drawer">
                    <button className="side-panel__close" onClick={() => setSidePanel(false)}>✕</button>

                    <div className="side-panel__logo">
                        <div className="side-panel__logo-mark">⛓</div>
                        <span>Proof of Precedence</span>
                    </div>

                    <div className="side-panel__divider" />

                    <nav className="side-panel__nav">
                        <div className="side-panel__nav-label">Navigate</div>
                        {[
                            { label: "Home",            icon: "⌂", action: () => { window.scrollTo({ top: 0, behavior: "smooth" }); setSidePanel(false); } },
                            { label: "How It Works",    icon: "⟳", action: () => { document.querySelector(".how-section")?.scrollIntoView({ behavior: "smooth" }); setSidePanel(false); } },
                            { label: "Technology",      icon: "⬡", action: () => { document.querySelector(".tech-section")?.scrollIntoView({ behavior: "smooth" }); setSidePanel(false); } },
                            { label: "Launch App",      icon: "↗", action: () => { onLaunchApp(); setSidePanel(false); } },
                        ].map(({ label, icon, action }) => (
                            <button className="side-panel__nav-item" key={label} onClick={action}>
                                <span className="side-panel__nav-icon">{icon}</span>
                                <span className="side-panel__nav-label-text">{label}</span>
                                <span className="side-panel__nav-arrow">›</span>
                            </button>
                        ))}
                    </nav>

                    <div className="side-panel__divider" />

                    <div className="side-panel__info">
                        <div className="side-panel__nav-label">Stack</div>
                        <div className="side-panel__tags">
                            {["Solidity 0.8", "Hardhat", "Ethers.js v6", "React", "IPFS", "Pinata", "Polygon", "EVM"].map(t => (
                                <span className="side-panel__tag" key={t}>{t}</span>
                            ))}
                        </div>
                    </div>

                    <div className="side-panel__footer">
                        © 2025 · All records immutable on-chain
                    </div>
                </div>
            </div>
        </>
    );
}
